import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.CKCxdkvf.js";const f=JSON.parse('{"title":"ADR-015 — Vitest for unit/integration tests, Playwright for e2e","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-015.md","filePath":"adr/ADR-015.md"}'),o={name:"adr/ADR-015.md"};function n(s,e,l,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-015-—-vitest-for-unit-integration-tests-playwright-for-e2e" tabindex="-1">ADR-015 — Vitest for unit/integration tests, Playwright for e2e <a class="header-anchor" href="#adr-015-—-vitest-for-unit-integration-tests-playwright-for-e2e" aria-label="Permalink to &quot;ADR-015 — Vitest for unit/integration tests, Playwright for e2e&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 TA anchor · §stack</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The orbital math library, data client, and router need unit test coverage. Critical user journeys need end-to-end coverage. A testing framework must be chosen.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Vitest for unit and integration tests. Playwright for end-to-end tests. Both run in GitHub Actions CI.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Vitest is Vite-native — same config, same transform pipeline, fast. SvelteKit&#39;s testing documentation recommends it. Playwright is the current standard for e2e testing: cross-browser, reliable, good SvelteKit integration. Together they cover the full testing pyramid without introducing a complex Jest configuration.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Jest</strong> — more familiar; slower with Vite projects; requires babel transform; rejected.</li><li><strong>Cypress</strong> — valid for e2e; heavier than Playwright; slower CI; rejected.</li><li><strong>Testing Library</strong> — component testing; useful addition later; not needed for Slice 1.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: fast unit tests; reliable e2e; both CI-ready out of the box. Negative: Playwright requires browser binaries in CI (~300MB download); cached after first run.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p><code>vitest</code> in <code>vite.config.ts</code>. Playwright config at <code>playwright.config.ts</code>. Unit tests colocated with source: <code>src/lib/orbital.test.ts</code>. E2e tests in <code>tests/</code>. CI caches Playwright browsers between runs.</p>',14)])])}const g=t(o,[["render",n]]);export{f as __pageData,g as default};
